using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class WeatherTools
{
    [McpServerTool(Name = "get_forecast"),
     Description("Get the weather forecast for a US location by latitude and longitude.")]
    public static async Task<string> GetForecast(
        IHttpClientFactory httpClientFactory,
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        var client = httpClientFactory.CreateClient("WeatherApi");

        // Step 1: Resolve grid coordinates from lat/lon
        var pointUrl = $"/points/{latitude:F4},{longitude:F4}";
        var point = await client.GetFromJsonAsync<JsonElement>(pointUrl);
        var forecastUrl = point.GetProperty("properties").GetProperty("forecast").GetString()
            ?? throw new InvalidOperationException("Forecast URL not found in point response.");

        // Step 2: Fetch the forecast
        var forecast = await client.GetFromJsonAsync<JsonElement>(forecastUrl);
        var periods = forecast.GetProperty("properties").GetProperty("periods");

        var results = periods.EnumerateArray()
            .Take(5)
            .Select(p =>
                $"""
                {p.GetProperty("name").GetString()}:
                  {p.GetProperty("temperature").GetInt32()}°{p.GetProperty("temperatureUnit").GetString()}
                  Wind: {p.GetProperty("windSpeed").GetString()} {p.GetProperty("windDirection").GetString()}
                  {p.GetProperty("shortForecast").GetString()}
                """);

        return string.Join("\n", results);
    }

    [McpServerTool(Name = "get_alerts"),
     Description("Get active weather alerts for a US state. Use two-letter state code (e.g. CA, NY).")]
    public static async Task<string> GetAlerts(
        IHttpClientFactory httpClientFactory,
        [Description("Two-letter US state code (e.g. CA, TX)")] string state)
    {
        var client = httpClientFactory.CreateClient("WeatherApi");

        var alerts = await client.GetFromJsonAsync<JsonElement>($"/alerts/active?area={state}");
        var features = alerts.GetProperty("features");

        if (features.GetArrayLength() == 0)
            return $"No active alerts for {state}.";

        var results = features.EnumerateArray()
            .Take(5)
            .Select(f =>
            {
                var props = f.GetProperty("properties");
                return $"""
                    Event: {props.GetProperty("event").GetString()}
                    Area: {props.GetProperty("areaDesc").GetString()}
                    Severity: {props.GetProperty("severity").GetString()}
                    {props.GetProperty("headline").GetString()}
                    """;
            });

        return string.Join("\n---\n", results);
    }
}

[AttributeUsage(AttributeTargets.Method | AttributeTargets.Parameter)]
public class DescriptionAttribute(string description) : Attribute
{
    public string Description { get; } = description;
}

